proof fn phi_1_instantiate_entailed_always_intensional_bridge(ex: Execution<int>, i: nat, spec: TempPred<int>, p: TempPred<int>)
    requires
        spec.satisfied_by(ex),
        spec.entails(always(p)),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    instantiate_entailed_always::<int>(ex, i, spec, p);
}

proof fn phi_2_instantiate_entailed_leads_to_intensional_bridge(ex: Execution<int>, i: nat, spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.satisfied_by(ex),
        spec.entails(p.leads_to(q)),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    instantiate_entailed_leads_to::<int>(ex, i, spec, p, q);
}

proof fn phi_3_borrow_false_inv_weakens_leads_to(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(always(TempPred::<int>::new(|ex: Execution<int>| false))),
    ensures
        spec.entails(p.leads_to(q)),
{
    leads_to_by_borrowing_inv::<int>(spec, p, q, TempPred::new(|ex: Execution<int>| false));
}

proof fn phi_4_borrow_trivial_inv_any_leads_to(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, inv: TempPred<int>)
    requires
        spec.entails(always(inv)),
        valid(inv.implies(TempPred::<int>::new(|ex: Execution<int>| false))),
    ensures
        spec.entails(p.leads_to(q)),
{
    leads_to_by_borrowing_inv::<int>(spec, p, q, inv);
}

proof fn phi_5_leads_to_self_trivial(spec: TempPred<int>, p: TempPred<int>, inv: TempPred<int>)
    requires
        spec.entails(always(inv)),
        spec.entails(p.and(inv).leads_to(p)),
    ensures
        spec.entails(p.leads_to(p)),
{
    leads_to_by_borrowing_inv::<int>(spec, p, p, inv);
}
